func (t *ToolExecutor) restart(args map[string]any) string {
	// Get the current executable path
	execPath, err := os.Executable()
	if err != nil {
		return fmt.Sprintf("Error getting executable path: %v", err)
	}

	// Determine directory for go build
	dir := filepath.Dir(execPath)

	// Rebuild the program
	buildCmd := exec.Command("go", "build", "-o", execPath, ".")
	buildCmd.Dir = dir

	output, err := buildCmd.CombinedOutput()
	if err != nil {
		return fmt.Sprintf("Error building: %v\n%s", err, string(output))
	}

	// Get the current arguments to pass to the new process
	newArgs := os.Args[1:] // Skip the executable name itself

	// Create the command for the new executable
	cmd := exec.Command(execPath, newArgs...)

	// Set up environment variables
	cmd.Env = append(os.Environ(), "YOLO_RESTARTING=1")

	// Capture output for logging before we lose our process
	var outputBuf bytes.Buffer
	cmd.Stdout = &outputBuf
	cmd.Stderr = &outputBuf

	// Start the new process
	if err := cmd.Start(); err != nil {
		return fmt.Sprintf("Error starting new process: %v", err)
	}

	// Wait a moment to let it initialize, then exit this process
	time.Sleep(100 * time.Millisecond)

	outputStr := outputBuf.String()
	os.Exit(0) // Exit current process after starting the new one

	return fmt.Sprintf("Restarted successfully!\n%s", outputStr) // This won't be reached due to os.Exit
}</parameter>
